class Bad {
    fun process() {
        try {
            throw RuntimeException("oops")
        } catch (e: Exception) { e.printStackTrace() }
    }
}

class Bad {
    fun process() {
        try {
            doSomething()
        } catch (e: RuntimeException) {
            e.printStackTrace()
        }
    }
    private fun doSomething() {}
}

class Bad {
    fun dump(t: Throwable) {
        t.printStackTrace()
    }
}

import mu.KotlinLogging

class Good {
    private val log = KotlinLogging.logger {}
    fun process() {
        try {
            doSomething()
        } catch (e: Exception) {
            log.error("error", e)
        }
    }
    private fun doSomething() {}
}

import mu.KotlinLogging

class Good {
    private val log = KotlinLogging.logger {}
    fun process() {
        runCatching { doSomething() }
            .onFailure { log.error("failed", it) }
    }
    private fun doSomething() {}
}
